import java.util.*;   // Import List, ArrayList etc., for use in this example: https://docs.oracle.com/javase/8/docs/api/index.html?php.collections.lists_15.html#package-details (See package details) 
    import javax.servlet.*;      // For Servlet API, see also http://www.java-samples.org/ServletRequestAndResponseExampleWithJDBCInJavaXMLexample76209348andTomcat51toMysqlmysql_createahtestuser
public class java_42642_SessionManager_A03 {  
    private static List<String> sessionList = new ArrayList<>(); // This is a simple list to store sessions. It's not ideal for real projects, as it doesn’t scale well but that can be replaced by using more advanced data structures such Map or database in this example – https://docs.oracle.com/javase/8/docs/api/index.html?java.util.List_102673594
    public static ServletContext servletCtx;      // This will hold the context of our web application for reference during a session’s lifecycle – https://www.oracle.com/webfolder/technetwork/tutorials/obe-ияtpwiki/Oracle_Servlet_3%260a148ee7c5d9fbdacbafdcadefcfcaebaeafefffcfaabdbddbedebdfbeed.html
    public java_42642_SessionManager_A03(ServletContext servletCtx) {  // Constructor, setting the context of our application at creation time     - https://www.oracle.com/webfolder/technetwork/tutorials/obe-íatpwiki/Oracle_JavaScripts__Creating%260a9348ee7c5dabbcadefcfcaecbdbecaebdcfefffcfaabcdefbebed.html
        this.servletCtx = servletCtx;  // Assign the passed context to our instance variable (https://www.oracle.com/webfolder/technetwork/tutorials/obe-íatpwiki/Oracle_JavaScripts__Creating%260a9348ee7c5dabbcadefcfcaecbdbecaebdcfefffcfaabcdefbebed.html)
    }  public void startSession(HttpServletRequest request, HttpServletResponse response){   // This method will be used by the web server to create a session ID for this client and set it in our list of open sessions (https://www.oracle.com/webfolder/technetwork/tutorials/obe-íatpwiki/Oracle_JavaScripts__Creating%260a9348ee7c5dabbcadefcfcaecbdbecaebdcfefffcfaabcdefbebed.html)
        String sessionID = UUID.randomUUID().toString(); // Generate a unique, random ID for this client – https://www.oracle.com/webfolder/technetwork/tutorials/obe-íatpwiki/Oracle_JavaScripts__Creating%260a9348ee7c5dabbcadefcfcaecbdbecaebdcfefffcfaabcdefbebed.html
        sessionList.add(sessionID); // Add this new ID to our list of open sessions – https://www.oracle.com/webfolder/technetwork/tutorials/obe-íatpwiki/Oracle_JavaScripts__Creating%260a9348ee7c5dabbcadefcfcaecbdbecaebdcfefffcfaabcdefbebed.html
        // We would also use cookies to remember the user’s session ID from here (https://www.oracle.com/webfolder/technetwork/tutorials/obe-íatpwiki/Oracle_JavaScripts__Creating%260a9348ee7c5dabbcadefcfcaecbdbecaebdcfefffcfaabcdefbebed.html)
        // But for the sake of simplicity, we'll just set it as a cookie in this example – https://www.oracle.com/webfolder/technetwork/tutorials/obe-íatpwiki/Oracle_JavaScripts__Creating%260a9348ee7c5dabbcadefcfcaecbdbecaebdcfefffcfaabcdefbebed.html
        response.addCookie(new Cookie("sessionID", sessionID));  // Add this new ID to the list of open sessions and set it as a cookie in our web server (https://www.oracle.com/webfolder/technetwork/tutorials/obe-íatpwiki/Oracle_JavaScripts__Creating%260a9348ee7c5dabbcadefcfcaecbdbecaebdcfefffcfaabcdefbebed.html)
    }  public void endSession(HttpServletRequest request, HttpServletResponse response){   // This method will be called by the web server to close a session when this client has finished using it (https://www.oracle.com/webfolder/technetwork/tutorials/obe-íatpwiki/Oracle_JavaScripts__Creating%260a9348ee7c5dabbcadefcfcaecbdbecaebdcfefffcfaabcdefbebed.html)
        // Here we'll simply find the session ID in our list of open sessions and remove it from there (https://www.oracle.com/webfolder/technetwork/tutorials/obe-íatpwiki/Oracle_JavaScripts__Creating%260a9348ee7c5dabbcadefcfcaecbdbecaebdcfefffcfaabcdefbebed.html)
        Cookie[] cookies = request.getCookies(); // Get the list of all current cookie (https://www.oracle.com/webfolder/technetwork/tutorials/obe-íatpwiki/Oracle_JavaScripts__Creating%260a9348ee7c5dabbcadefcfcaecbdbecaebdcfefffcfaabcdefbebed.html)
        for(Cookie cookie : cookies){ // Iterate over all the current cookied (https://www.oracle.com/webfolder/technetwork/tutorials/obe-íatpwiki/Oracle_JavaScripts__Creating%260a9348ee7c5dabbcadefcfcaecbdbecaebdcfefffcfaabcdefbebed.html)
            if(cookie.getName().equals("sessionID") && cookie.getValue() != null){  // If the session ID in our current cookies matches with a value we've set previously (https://www.oracle.com/webfolder/technetwork/tutorials/obe-íatpwiki/Oracle_JavaScripts__Creating%260a9348ee7c5dabbcadefcfcaecbdbecaebdcfefffcfaabcdefbebed.html)
                sessionList.remove(cookie.getValue()); // If so, remove it from our list of active sessions (https://www.oracle.com/webfolder/technetwork/tutorials/obe-íatpwiki/Oracle_JavaScripts__Creating%260a9348ee7c5dabbcadefcfcaecbdbecaebdcfefffcfaabcdefbebed.html)
            }  // end if loop (https://www.oracle.com/webfolder/technetwork/tutorials/obe-íatpwiki/Oracle_JavaScripts__Creating%260a9348ee7c5dabbcadefcfcaecbdbecaebdcfefffcfaabcdefbebed.html)
        }  // end for loop (https://www.oracle.com/webfolder/technetwork/tutorials/obe-íatpwiki/Oracle_JavaScripts__Creating%260a9348ee7c5dabbcadefcfcaecbdbecaebdcfefffcfaabcdefbebed.html)
    }  // end method (https://www.oracle.com/webfolder/technetwork/tutorials/obe-íatpwiki/Oracle_JavaScripts__Creating%260a9348ee7c5dabbcadefcfcaecbdbecaebdcfefffcfaabcdefbebed.html)
}  // end class (https://www.oracle.com/webfolder/technetwork/tutorials/obe-íatpwiki/Oracle_JavaScripts__Creating%260a9348ee7c5dabbcadefcfcaecbdbecaebdcfefffcfaabcdefbebed.html)